import React, { useEffect, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { explainError } from "./errorHelper";

function RunCodePage() {
  const location = useLocation();
  const navigate = useNavigate();

  const code = location.state?.code || "";
  const input = location.state?.input || ""; // ✅ stdin support

  const [output, setOutput] = useState("Running...");
  const [errorData, setErrorData] = useState(null);

  useEffect(() => {
    runCode();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const runCode = () => {
    const logs = [];
    const originalLog = console.log;
    const originalError = console.error;
    const originalWarn = console.warn;
    const originalPrompt = window.prompt;

    try {
      // 1. Capture console logs, errors, and warnings
      console.log = (...args) => {
        logs.push(
          args
            .map((arg) => (typeof arg === "object" ? JSON.stringify(arg) : arg))
            .join(" ")
        );
      };
      console.error = (...args) => {
        logs.push("[ERROR] " + args.join(" "));
      };
      console.warn = (...args) => {
        logs.push("[WARN] " + args.join(" "));
      };

      // 2. Mock prompt() for standard input (stdin) support
      let inputLines = input ? input.split("\n") : [];
      let inputIndex = 0;
      window.prompt = () => {
        if (inputIndex < inputLines.length) {
          return inputLines[inputIndex++];
        }
        return null;
      };

      // 3. Execute the code safely in a function scope
      // eslint-disable-next-line no-eval
      eval(code);

      // 4. Update output UI
      setOutput(logs.join("\n") || "No Output");
      setErrorData(null);
    } catch (err) {
      // 5. Catch runtime errors and use explainError helper
      const errorMsg = err.stack || err.toString();
      setOutput(errorMsg);
      setErrorData(explainError(errorMsg));
    } finally {
      // 6. Restore original browser functions
      console.log = originalLog;
      console.error = originalError;
      console.warn = originalWarn;
      window.prompt = originalPrompt;
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <button onClick={() => navigate("/")}>⬅ Back</button>
        <h2>Output (Judge0)</h2>
      </div>

      <pre style={styles.output}>{output}</pre>

      {errorData && (
        <div style={styles.errorBox}>
          <h3>🧠 Samjho kya galat hua:</h3>
          <p><b>{errorData.message}</b></p>
          <p>{errorData.explanation}</p>

          <h4>✅ Kaise thik kare:</h4>
          <p>{errorData.fix}</p>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: {
    background: "#1e1e1e",
    color: "#fff",
    height: "100vh",
    padding: "10px",
  },
  header: {
    display: "flex",
    gap: "10px",
    alignItems: "center",
  },
  output: {
    marginTop: "20px",
    background: "#000",
    padding: "15px",
    minHeight: "200px",
  },
  errorBox: {
    marginTop: "20px",
    padding: "15px",
    background: "#2d1e1e",
    border: "1px solid red",
  },
};

export default RunCodePage;
